// Fuzzy search: returns top N matches for a query string
export function searchSchools(query, limit = 10) {
  if (!query || query.trim().length < 2) return [];
  const q = query.trim().toUpperCase();
  const words = q.split(/s+/);

  const scored = ZIMBABWE_SCHOOLS.map(school => {
    // Exact start match = highest score
    if (school.startsWith(q)) return { school, score: 100 };
    // All words present
    const allWords = words.every(w => school.includes(w));
    if (allWords) return { school, score: 80 };
    // First word match
    if (school.startsWith(words[0])) return { school, score: 60 };
    // Any word match
    const anyWord = words.some(w => w.length > 3 && school.includes(w));
    if (anyWord) return { school, score: 40 };
    // Substring anywhere
    if (school.includes(q.substring(0, Math.min(q.length, 6)))) return { school, score: 20 };
    return { school, score: 0 };
  }).filter(x => x.score > 0)
    .sort((a, b) => b.score - a.score || a.school.localeCompare(b.school));

  return scored.slice(0, limit).map(x => x.school);
}